import collections

def is_bipartite(graph):
    colors = {}

    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        all_nodes.update(neighbors)

    for node in all_nodes:
        if node not in colors:
            q = collections.deque()
            q.append(node)
            colors[node] = 0

            while q:
                u = q.popleft()

                for v in graph.get(u, []):
                    if v not in colors:
                        colors[v] = 1 - colors[u]
                        q.append(v)
                    elif colors[v] == colors[u]:
                        return False
    return True
